class Solution(object):
    def maxScoreIndices(self, nums):
        n = len(nums)
        total_ones = sum(nums)
        max_score = 0
        scores = []
        left_zeros = 0
        right_ones = total_ones
        for i in range(n + 1):
            score = left_zeros + right_ones
            if score > max_score:
                max_score = score
                scores = [i]
            elif score == max_score:
                scores.append(i)
            if i < n:
                if nums[i] == 0:
                    left_zeros += 1
                else:
                    right_ones -= 1
        return scores
